"use client";

import { useEffect, useState, useRef } from "react";
import Navbar from "@/components/Navbar";
import { useRouter } from "next/navigation";
import {
  Sprout,
  Scale,
  DollarSign,
  Image as ImageIcon,
  ArrowRight,
  ArrowLeft,
  CheckCircle,
  AlertCircle
} from 'lucide-react';

// Tipos
interface Produto {
  id: number;
  nome: string;
  categoria: string;
}

export default function NovaSafraPage() {
  const router = useRouter();
  const [produtos, setProdutos] = useState<Produto[]>([]);
  const [loadingProdutos, setLoadingProdutos] = useState(true);

  // Estado do Formulário
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    produto_id: "",
    quantidade_kg: "",
    preco_kg: "",
    descricao: "",
    imagem_safra: null as File | null
  });
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");

  // Referência para o input de arquivo oculto
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Carregar produtos
    fetch("http://localhost:5000/api/v1/produtos")
      .then(res => res.json())
      .then(json => {
        if (json.success) setProdutos(json.data);
      })
      .catch(err => console.error("Erro ao carregar produtos", err))
      .finally(() => setLoadingProdutos(false));
  }, []);

  // Handlers
  const handleChange = (field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setError("");
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setFormData(prev => ({ ...prev, imagem_safra: file }));
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const validateStep = (currentStep: number) => {
    if (currentStep === 1 && !formData.produto_id) {
      setError("Por favor, selecione um produto para continuar.");
      return false;
    }
    if (currentStep === 2) {
      if (!formData.quantidade_kg || parseFloat(formData.quantidade_kg) <= 0) {
        setError("Indique uma quantidade válida maior que zero.");
        return false;
      }
      if (!formData.preco_kg || parseFloat(formData.preco_kg) <= 0) {
        setError("Indique um preço válido maior que zero.");
        return false;
      }
    }
    return true;
  };

  const nextStep = () => {
    if (validateStep(step)) {
      setStep(prev => prev + 1);
      setError("");
    }
  };

  const prevStep = () => {
    setStep(prev => prev - 1);
    setError("");
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      const token = localStorage.getItem("token");
      const data = new FormData();
      data.append("produto_id", formData.produto_id);
      data.append("quantidade_kg", formData.quantidade_kg);
      data.append("preco_kg", formData.preco_kg);
      data.append("descricao", formData.descricao);
      if (formData.imagem_safra) {
        data.append("imagem_safra", formData.imagem_safra);
      }

      const res = await fetch("http://localhost:5000/api/v1/produtor/nova-safra", {
        method: "POST",
        headers: { "Authorization": `Bearer ${token}` },
        body: data
      });

      const json = await res.json();
      if (json.success) {
        router.push("/produtor/vendas?sucesso=true");
      } else {
        setError(json.error || "Erro ao publicar safra.");
      }
    } catch (err) {
      setError("Erro de conexão. Tente novamente.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Obter nome do produto selecionado
  const selectedProdutoNome = produtos.find(p => p.id.toString() === formData.produto_id)?.nome;

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Navbar />

      <main className="flex-1 flex flex-col items-center justify-center p-4">

        {/* Progress Bar */}
        <div className="w-full max-w-2xl mb-8">
          <div className="flex justify-between mb-2 text-sm font-medium text-gray-500">
            <span className={step >= 1 ? "text-green-600" : ""}>Produto</span>
            <span className={step >= 2 ? "text-green-600" : ""}>Detalhes</span>
            <span className={step >= 3 ? "text-green-600" : ""}>Visual</span>
            <span className={step >= 4 ? "text-green-600" : ""}>Revisão</span>
          </div>
          <div className="h-2 bg-gray-200 rounded-full overflow-hidden">
            <div
              className="h-full bg-green-600 transition-all duration-500 ease-out"
              style={{ width: `${(step / 4) * 100}%` }}
            ></div>
          </div>
        </div>

        {/* Card Principal */}
        <div className="bg-white w-full max-w-2xl rounded-3xl shadow-xl overflow-hidden relative min-h-[500px] flex flex-col">

          {/* Header do Passo */}
          <div className="bg-green-50 p-8 border-b border-green-100">
            <h1 className="text-2xl font-bold text-green-900 flex items-center gap-3">
              {step === 1 && <><Sprout className="text-green-600" /> O que vai colher hoje?</>}
              {step === 2 && <><Scale className="text-green-600" /> Defina os valores</>}
              {step === 3 && <><ImageIcon className="text-green-600" /> Mostre o seu produto</>}
              {step === 4 && <><CheckCircle className="text-green-600" /> Confirmar Publicação</>}
            </h1>
            <p className="text-green-700 mt-2">
              {step === 1 && "Escolha o produto que deseja vender no mercado."}
              {step === 2 && "Indique a quantidade disponível e o preço por quilo."}
              {step === 3 && "Uma boa foto aumenta as suas hipóteses de venda."}
              {step === 4 && "Verifique se está tudo correto antes de publicar."}
            </p>
          </div>

          {/* Corpo do Formulário */}
          <div className="p-8 flex-1">
            {error && (
              <div className="mb-6 bg-red-50 text-red-700 p-4 rounded-xl flex items-center gap-3 animate-pulse">
                <AlertCircle size={20} />
                {error}
              </div>
            )}

            {/* PASSO 1: Seleção de Produto */}
            {step === 1 && (
              <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                {loadingProdutos ? (
                  <p>A carregar produtos...</p>
                ) : (
                  produtos.map((p) => (
                    <button
                      key={p.id}
                      onClick={() => {
                        handleChange("produto_id", p.id.toString());
                        setError("");
                      }}
                      className={`
                        p-4 rounded-xl border-2 text-left transition-all hover:shadow-md flex flex-col items-center justify-center gap-2 h-32
                        ${formData.produto_id === p.id.toString()
                          ? 'border-green-500 bg-green-50 text-green-800 ring-2 ring-green-500 ring-opacity-50'
                          : 'border-gray-100 bg-white hover:border-green-200 text-gray-600'}
                      `}
                    >
                      <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center shadow-sm text-lg">
                        {p.nome.charAt(0)}
                      </div>
                      <span className="font-semibold">{p.nome}</span>
                      <span className="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">{p.categoria}</span>
                    </button>
                  ))
                )}
              </div>
            )}

            {/* PASSO 2: Quantidade e Preço */}
            {step === 2 && (
              <div className="space-y-8 animate-fadeIn">
                <div className="relative">
                  <label className="block text-sm font-bold text-gray-700 mb-2">Quantidade Disponível (Kg)</label>
                  <div className="flex items-center border-2 border-gray-200 rounded-xl focus-within:border-green-500 focus-within:ring-4 focus-within:ring-green-100 transition-all overflow-hidden">
                    <div className="bg-gray-50 px-4 py-4 border-r border-gray-200">
                      <Scale className="text-gray-400" />
                    </div>
                    <input
                      type="number"
                      value={formData.quantidade_kg}
                      onChange={(e) => handleChange("quantidade_kg", e.target.value)}
                      className="w-full p-4 outline-none text-lg font-bold text-gray-800 placeholder-gray-300"
                      placeholder="0.00"
                      autoFocus
                    />
                    <span className="pr-6 font-bold text-gray-400">KG</span>
                  </div>
                </div>

                <div className="relative">
                  <label className="block text-sm font-bold text-gray-700 mb-2">Preço por Quilo (Kz)</label>
                  <div className="flex items-center border-2 border-gray-200 rounded-xl focus-within:border-green-500 focus-within:ring-4 focus-within:ring-green-100 transition-all overflow-hidden">
                    <div className="bg-gray-50 px-4 py-4 border-r border-gray-200">
                      <DollarSign className="text-gray-400" />
                    </div>
                    <input
                      type="number"
                      value={formData.preco_kg}
                      onChange={(e) => handleChange("preco_kg", e.target.value)}
                      className="w-full p-4 outline-none text-lg font-bold text-gray-800 placeholder-gray-300"
                      placeholder="0.00"
                    />
                    <span className="pr-6 font-bold text-gray-400">KZ</span>
                  </div>
                </div>
              </div>
            )}

            {/* PASSO 3: Imagem e Descrição */}
            {step === 3 && (
              <div className="space-y-6 animate-fadeIn">
                <div
                  className={`
                    border-3 border-dashed rounded-2xl p-8 text-center cursor-pointer transition-all
                    ${previewUrl ? 'border-green-500 bg-green-50' : 'border-gray-300 hover:border-green-400 hover:bg-gray-50'}
                  `}
                  onClick={() => fileInputRef.current?.click()}
                >
                  <input
                    type="file"
                    ref={fileInputRef}
                    className="hidden"
                    accept="image/*"
                    onChange={handleFileSelect}
                  />

                  {previewUrl ? (
                    <div className="relative h-64 w-full">
                      <img src={previewUrl} alt="Preview" className="h-full w-full object-contain rounded-lg" />
                      <p className="mt-4 text-green-600 font-medium">Clique para alterar a foto</p>
                    </div>
                  ) : (
                    <div className="py-10">
                      <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                        <ImageIcon size={32} />
                      </div>
                      <h3 className="text-lg font-bold text-gray-700">Carregar Foto do Produto</h3>
                      <p className="text-gray-500 mt-2">Formatos: JPG, PNG (Max 10MB)</p>
                    </div>
                  )}
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-2">Descrição (Opcional)</label>
                  <textarea
                    rows={3}
                    className="w-full p-4 border-2 border-gray-200 rounded-xl focus:border-green-500 focus:ring-4 focus:ring-green-100 outline-none transition-all resize-none"
                    placeholder="Ex: Batata doce de polpa laranja, muito doce..."
                    value={formData.descricao}
                    onChange={(e) => handleChange("descricao", e.target.value)}
                  />
                </div>
              </div>
            )}

            {/* PASSO 4: Revisão */}
            {step === 4 && (
              <div className="bg-gray-50 rounded-2xl p-6 border border-gray-200 animate-fadeIn">
                <div className="flex gap-6">
                  <div className="w-32 h-32 bg-white rounded-xl shadow-sm overflow-hidden flex-shrink-0">
                    {previewUrl ? (
                      <img src={previewUrl} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center bg-gray-100 text-gray-400">
                        <ImageIcon />
                      </div>
                    )}
                  </div>
                  <div className="space-y-3 flex-1">
                    <div>
                      <p className="text-xs text-gray-500 uppercase tracking-wide">Produto</p>
                      <p className="text-xl font-bold text-gray-900">{selectedProdutoNome}</p>
                    </div>
                    <div className="flex gap-8">
                      <div>
                        <p className="text-xs text-gray-500 uppercase tracking-wide">Quantidade</p>
                        <p className="text-lg font-semibold text-gray-800">{formData.quantidade_kg} Kg</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-500 uppercase tracking-wide">Preço/Kg</p>
                        <p className="text-lg font-semibold text-green-600">{formData.preco_kg} Kz</p>
                      </div>
                    </div>
                    <div>
                        <p className="text-xs text-gray-500 uppercase tracking-wide">Total Estimado</p>
                        <p className="text-lg font-bold text-gray-900">
                          {(parseFloat(formData.quantidade_kg) * parseFloat(formData.preco_kg)).toLocaleString('pt-AO')} Kz
                        </p>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Footer com Botões */}
          <div className="p-6 border-t border-gray-100 flex justify-between bg-white sticky bottom-0">
            {step > 1 ? (
              <button
                onClick={prevStep}
                className="px-6 py-3 rounded-xl border-2 border-gray-200 text-gray-600 font-bold hover:bg-gray-50 transition-colors flex items-center gap-2"
              >
                <ArrowLeft size={20} /> Voltar
              </button>
            ) : (
              <div></div> // Espaçador
            )}

            {step < 4 ? (
              <button
                onClick={nextStep}
                className="px-8 py-3 rounded-xl bg-green-600 text-white font-bold hover:bg-green-700 transition-transform hover:scale-105 shadow-lg shadow-green-200 flex items-center gap-2"
              >
                Continuar <ArrowRight size={20} />
              </button>
            ) : (
              <button
                onClick={handleSubmit}
                disabled={isSubmitting}
                className="px-8 py-3 rounded-xl bg-green-800 text-white font-bold hover:bg-green-900 transition-all shadow-xl flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
              >
                {isSubmitting ? (
                  <>
                    <span className="animate-spin h-5 w-5 border-2 border-white border-t-transparent rounded-full"></span>
                    A Publicar...
                  </>
                ) : (
                  <>Publicar Agora <CheckCircle size={20} /></>
                )}
              </button>
            )}
          </div>

        </div>
      </main>
    </div>
  );
}